def generate_numbers(digits, length):
    if length == 0:
        return [""]
    smaller_numbers = generate_numbers(digits, length - 1)
    result = []
    for number in smaller_numbers:
        for digit in digits:
            result.append(number + str(digit))
    return result

def filter_numbers(numbers):
